SELECT metro_code, metro_name, median_home_price
FROM metros
WHERE median_home_price = (
  SELECT MAX(median_home_price)
  FROM metros
);

SELECT metro_code, metro_name, population, region_code, median_income, crime_rate, public_transportation_score, number_of_hospitals
FROM metros
WHERE metro_area_type = 'urban' AND median_income > 50000 AND crime_rate < 10.0 AND public_transportation_score > 80 AND number_of_hospitals < 5;

SELECT metros.metro_name, regions.region_name
FROM metros
JOIN regions ON metros.region_code = regions.region_code;

SELECT *
FROM property_details
WHERE value > (SELECT AVG(value) FROM property_details);

SELECT COUNT(*) AS number_of_assisted_housing_properties
FROM financials
WHERE assisted = 1;
